## Deadline Watch
<%*
const deadlines = {
  "NeurIPS Abstract": "2026-05-15",
  "NeurIPS Submission": "2026-05-22",
  "Thesis Proposal": "2026-09-01",
  "ICLR 2027": "2026-10-01"
};

let output = "| Event | Date | Days Left | Status |\n| :--- | :--- | :--- | :--- |\n";

for (const [name, dateStr] of Object.entries(deadlines)) {
  const target = moment(dateStr);
  const today = moment();
  const diff = target.diff(today, 'days');
  let status = "🟢 On Track";

  if (diff < 0) status = "🏁 Passed";
  else if (diff <= 7) status = "🔴 URGENT";
  else if (diff <= 30) status = "🟠 Looming";

  output += `| ${name} | ${dateStr} | ${diff} | ${status} |\n`;
}
tR += output;
%>

